from flask import Flask, request, redirect, session, render_template, url_for
from flask_sqlalchemy import SQLAlchemy
from flask_mail import Mail, Message
import random
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.urandom(24)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['MAIL_SERVER'] = 'smtp.example.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = 'your_email@example.com'
app.config['MAIL_PASSWORD'] = 'your_password'
db = SQLAlchemy(app)
mail = Mail(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(150), unique=True, nullable=False)
    password = db.Column(db.String(150), nullable=False)
    email = db.Column(db.String(150), unique=True, nullable=False)

db.create_all()

def send_mfa_code(email, code):
    msg = Message('Your MFA Code', sender='your_email@example.com', recipients=[email])
    msg.body = f'Your MFA code is: {code}'
    mail.send(msg)

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']
    user = User.query.filter_by(username=username, password=password).first()
    if user:
        session['user_id'] = user.id
        mfa_code = random.randint(100000, 999999)
        session['mfa_code'] = mfa_code
        send_mfa_code(user.email, mfa_code)
        return redirect(url_for('verify_mfa'))
    return 'Invalid credentials', 401

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if request.method == 'POST':
        entered_code = request.form['mfa_code']
        if str(entered_code) == str(session.get('mfa_code')):
            session['authenticated'] = True
            return redirect(url_for('protected_resource'))
        return 'Invalid MFA code', 401
    return render_template('verify_mfa.html')

@app.route('/protected-resource')
def protected_resource():
    if not session.get('authenticated'):
        return redirect(url_for('login'))
    return 'This is a protected resource.'

if __name__ == '__main__':
    app.run(debug=True)